input.command:
cat << 'EOF' > /etc/nginx/conf.d/benchmark-site.conf
server {
    listen 8080;
    server_name localhost;

    root /var/www/html;
    index index.html;

    access_log /var/log/nginx/benchmark-access.log benchmark_log;
    error_log /var/log/nginx/benchmark-error.log;

    limit_req zone=benchmark_zone burst=10;

    error_page 404 /404.html;

    location = /404.html {
        internal;
    }

    location / {
        try_files $uri $uri/ =404;
    }
}
EOF

